const AWS = require('aws-sdk');
const s3 = new AWS.S3();
const crypto = require('crypto');

const BUCKET_NAME = process.env.BUCKET_NAME;
const MAX_FILE_SIZE = 10 * 1024 * 1024; // 10MB
const ALLOWED_CONTENT_TYPES = [
  'image/jpeg',
  'image/png',
  'image/gif',
  'image/webp',
  'application/pdf',
  'text/plain',
  'text/csv'
];
const MAX_UPLOADS_PER_IP = 10;
const RATE_LIMIT_WINDOW = 3600; // 1 hour in seconds

const dynamodb = new AWS.DynamoDB.DocumentClient();
const RATE_LIMIT_TABLE = process.env.RATE_LIMIT_TABLE || 'upload-rate-limits';

async function checkRateLimit(ipAddress) {
  const now = Math.floor(Date.now() / 1000);
  const windowStart = now - RATE_LIMIT_WINDOW;

  try {
    const result = await dynamodb.get({
      TableName: RATE_LIMIT_TABLE,
      Key: { ipAddress }
    }).promise();

    if (result.Item) {
      const recentUploads = result.Item.uploads.filter(timestamp => timestamp > windowStart);
      
      if (recentUploads.length >= MAX_UPLOADS_PER_IP) {
        return false;
      }

      await dynamodb.update({
        TableName: RATE_LIMIT_TABLE,
        Key: { ipAddress },
        UpdateExpression: 'SET uploads = :uploads, lastUpdate = :now, expiresAt = :expiresAt',
        ExpressionAttributeValues: {
          ':uploads': [...recentUploads, now],
          ':now': now,
          ':expiresAt': now + RATE_LIMIT_WINDOW + 86400
        }
      }).promise();
    } else {
      await dynamodb.put({
        TableName: RATE_LIMIT_TABLE,
        Item: {
          ipAddress,
          uploads: [now],
          lastUpdate: now,
          expiresAt: now + RATE_LIMIT_WINDOW + 86400
        }
      }).promise();
    }

    return true;
  } catch (error) {
    console.error('Rate limit check error:', error);
    return false;
  }
}

function validateContentType(contentType) {
  return ALLOWED_CONTENT_TYPES.includes(contentType);
}

function sanitizeFilename(filename) {
  return filename
    .replace(/[^a-zA-Z0-9._-]/g, '_')
    .substring(0, 255);
}

function detectMimeType(buffer, declaredType) {
  const signatures = {
    'image/jpeg': [0xFF, 0xD8, 0xFF],
    'image/png': [0x89, 0x50, 0x4E, 0x47],
    'image/gif': [0x47, 0x49, 0x46],
    'application/pdf': [0x25, 0x50, 0x44, 0x46]
  };

  for (const [mimeType, signature] of Object.entries(signatures)) {
    if (buffer.length >= signature.length) {
      const matches = signature.every((byte, index) => buffer[index] === byte);
      if (matches) {
        return mimeType === declaredType;
      }
    }
  }

  return declaredType === 'text/plain' || declaredType === 'text/csv';
}

exports.handler = async (event) => {
  const headers = {
    'Content-Type': 'application/json',
    'X-Content-Type-Options': 'nosniff',
    'X-Frame-Options': 'DENY',
    'Strict-Transport-Security': 'max-age=31536000; includeSubDomains',
    'Access-Control-Allow-Origin': process.env.ALLOWED_ORIGIN || 'https://yourdomain.com',
    'Access-Control-Allow-Methods': 'POST, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type'
  };

  if (event.httpMethod === 'OPTIONS') {
    return {
      statusCode: 200,
      headers,
      body: ''
    };
  }

  try {
    const ipAddress = event.requestContext?.identity?.sourceIp || 'unknown';
    
    const rateLimitOk = await checkRateLimit(ipAddress);
    if (!rateLimitOk) {
      return {
        statusCode: 429,
        headers,
        body: JSON.stringify({ error: 'Rate limit exceeded. Please try again later.' })
      };
    }

    const contentType = event.headers['content-type'] || event.headers['Content-Type'];
    
    if (!validateContentType(contentType)) {
      return {
        statusCode: 400,
        headers,
        body: JSON.stringify({ error: 'Invalid content type. Allowed types: ' + ALLOWED_CONTENT_TYPES.join(', ') })
      };
    }

    let fileBuffer;
    if (event.isBase64Encoded) {
      fileBuffer = Buffer.from(event.body, 'base64');
    } else {
      fileBuffer = Buffer.from(event.body);
    }

    if (fileBuffer.length > MAX_FILE_SIZE) {
      return {
        statusCode: 400,
        headers,
        body: JSON.stringify({ error: `File size exceeds maximum allowed size of ${MAX_FILE_SIZE / 1024 / 1024}MB` })
      };
    }

    if (fileBuffer.length === 0) {
      return {
        statusCode: 400,
        headers,
        body: JSON.stringify({ error: 'File content is empty' })
      };
    }

    if (!detectMimeType(fileBuffer, contentType)) {
      return {
        statusCode: 400,
        headers,
        body: JSON.stringify({ error: 'File content does not match declared content type' })
      };
    }

    const filename = event.queryStringParameters?.filename || 'upload';
    const sanitizedFilename = sanitizeFilename(filename);
    const fileId = crypto.randomBytes(16).toString('hex');
    const timestamp = Date.now();
    const key = `uploads/${timestamp}-${fileId}-${sanitizedFilename}`;

    const uploadParams = {
      Bucket: BUCKET_NAME,
      Key: key,
      Body: fileBuffer,
      ContentType: contentType,
      ServerSideEncryption: 'AES256',
      Metadata: {
        'uploaded-by': 'public-api',
        'upload-ip': ipAddress,
        'upload-timestamp': timestamp.toString()
      },
      Tagging: 'source=public-upload&reviewed=false'
    };

    await s3.putObject(uploadParams).promise();

    return {
      statusCode: 200,
      headers,
      body: JSON.stringify({
        message: 'File uploaded successfully',
        fileId: fileId,
        key: key
      })
    };

  } catch (error) {
    console.error('Upload error:', error);
    
    return {
      statusCode: 500,
      headers,
      body: JSON.stringify({ error: 'Internal server error' })
    };
  }
};